mapper.select:
/* TM_PN50001_Dao_retrieveRecIssList */ SELECT /*+ LEADING(MAPPING STDR_MAPPING DATAS) */ DATAS.prdctn_year, DATAS.rec_eqp_cd_nm, MAPPING.cmmn_cd_nm AS elcpwstn_nm, DATAS.mon01_iem_vu, DATAS.mon02_iem_vu, DATAS.mon03_iem_vu, DATAS.mon04_iem_vu, DATAS.mon05_iem_vu, DATAS.mon06_iem_vu, DATAS.mon07_iem_vu, DATAS.mon08_iem_vu, DATAS.mon09_iem_vu, DATAS.mon10_iem_vu, DATAS.mon11_iem_vu, DATAS.mon12_iem_vu, ROUND(( NVL(mon01_iem_vu, 0) + NVL(mon02_iem_vu, 0) + NVL(mon03_iem_vu, 0) + NVL(mon04_iem_vu, 0) + NVL(mon05_iem_vu, 0) + NVL(mon06_iem_vu, 0) + NVL(mon07_iem_vu, 0) + NVL(mon08_iem_vu, 0) + NVL(mon09_iem_vu, 0) + NVL(mon10_iem_vu, 0) + NVL(mon11_iem_vu, 0) + NVL(mon12_iem_vu, 0) ), 0) AS sum, DATAS.frst_regist_dt, DATAS.frst_rgstr_id, DATAS.last_updt_dt, DATAS.last_updusr_id, DATAS.updt_rsn FROM tm_pn50001 DATAS, ( SELECT cmmn_cd, cmmn_cd_nm, cmmn_cd_dc, upper_cmmn_cd, usr_dfn_vu1 FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2003' ) MAPPING, WRO.tc_eg10101 STDR_MAPPING WHERE DATAS.rec_eqp_cd_nm = MAPPING.cmmn_cd AND MAPPING.usr_dfn_vu1 = STDR_MAPPING.elcpwstn_cd(+) AND DATAS.prdctn_year = SUBSTR(#{strtDt}, 0, 4)
AND IN ( SELECT objid FROM (
) WHERE 1 = 1 AND cmmn_cd = #{ecsBasinDivCd} )
AND MAPPING.upper_cmmn_cd IN ( SELECT cmmn_cd, REGEXP_SUBSTR(cmmn_cd_nm, '[^(]+') AS cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1001' AND cmmn_cd = #{ecsSetcscDivCd} )
AND DATAS.rec_eqp_cd_nm = #{ecsElcpwstnDivCd}
ORDER BY DATAS.prdctn_year, DATAS.rec_eqp_cd_nm

mapper.delete:
/* TM_PN50001_Dao_deleteRecIssList */
DELETE FROM
	tm_pn50001
WHERE
	prdctn_year = #{prdctnYear}
	AND rec_eqp_cd_nm = #{recEqpCdNm}
